code = """import json
import re

# Load literature & fiction books
books_key = 'var_functions.query_db:34'
books_file = locals()[books_key]
if isinstance(books_file, str):
    with open(books_file, 'r') as f:
        lit_fiction_books = json.load(f)
else:
    lit_fiction_books = books_file

# Load all reviews
reviews_key = 'var_functions.query_db:38'
reviews_file = locals()[reviews_key]
if isinstance(reviews_file, str):
    with open(reviews_file, 'r') as f:
        all_reviews = json.load(f)
else:
    all_reviews = reviews_file

# Create mapping: book_id -> list of ratings
book_ratings = {}

# Build a mapping from purchase_id to ratings
purchase_to_ratings = {}
for review in all_reviews:
    purchase_id = review['purchase_id']
    rating = float(review['rating'])
    
    if purchase_id not in purchase_to_ratings:
        purchase_to_ratings[purchase_id] = []
    purchase_to_ratings[purchase_id].append(rating)

# Create book mapping
for book in lit_fiction_books:
    book_id = book['book_id']
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        book_num = int(match.group(1))
        purchase_id = f'purchaseid_{book_num}'
        
        if purchase_id in purchase_to_ratings:
            book_ratings[book_id] = purchase_to_ratings[purchase_id]

# Find books with perfect 5.0 average
perfect_books = []
for book_id, ratings in book_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating == 5.0:
        # Find the book details
        book_details = None
        for book in lit_fiction_books:
            if book['book_id'] == book_id:
                book_details = book
                break
        
        if book_details:
            perfect_books.append({
                'book_id': book_id,
                'title': book_details['title'],
                'average_rating': avg_rating,
                'rating_count': len(ratings),
                'categories': book_details['categories'],
                'details': book_details['details']
            })

print('__RESULT__:')
print(json.dumps(perfect_books))"""

